 // Reliable cross-device font loading using FontFace API with fallback
 var fontLoadedPromise = (function() {
     var fontUrl = 'https://fonts.gstatic.com/s/notosansarabic/v28/nwpCtLGrOAZMl5nJ_wfgRg3DrWFZWsnVBJ_sS6tlqHHFlj4wv4o.woff2';
 
     function loadFontFallback() {
         return new Promise(function(resolve) {
             fetch(fontUrl).then(function(response) {
                 return response.blob();
             }).then(function(fontBlob) {
                 var reader = new FileReader();
                 reader.onloadend = function() {
                     var fontBase64 = reader.result.split(',')[1];
                     var cssRule = '@font-face { font-family: "NotoSansArabic"; src: url(data:font/woff2;base64,' + fontBase64 + ') format("woff2"); }';
                     var style = document.createElement('style');
                     style.textContent = cssRule;
                     document.head.appendChild(style);
                     document.body.style.fontFamily = "'NotoSansArabic', sans-serif";
                     if (document.fonts && document.fonts.ready) {
                         document.fonts.ready.then(function() {
                             console.log('Font loaded via fallback + fonts.ready');
                             resolve(true);
                         });
                     } else {
                         setTimeout(function() { resolve(true); }, 500);
                     }
                 };
                 reader.readAsDataURL(fontBlob);
             }).catch(function(err) {
                 console.error('Error loading font:', err);
                 resolve(false);
             });
         });
     }
 
     if (typeof FontFace !== 'undefined') {
         return fetch(fontUrl).then(function(response) {
             return response.arrayBuffer();
         }).then(function(buffer) {
             var font = new FontFace('NotoSansArabic', buffer);
             return font.load();
         }).then(function(loadedFont) {
             document.fonts.add(loadedFont);
             document.body.style.fontFamily = "'NotoSansArabic', sans-serif";
             console.log('Font loaded via FontFace API');
             return true;
         }).catch(function(err) {
             console.warn('FontFace API failed, trying fallback:', err);
             return loadFontFallback();
         });
     } else {
         return loadFontFallback();
     }
 })();
 
 
 
 
          
 
