// =========== Helper functions for canvas text (بنات) ===========
function getWrappedLines(ctx, text, maxWidth) {
    const words = text.split(' ');
    let line = '';
    const lines = [];
    
    for (let i = 0; i < words.length; i++) {
        const testLine = line + words[i] + ' ';
        const testWidth = ctx.measureText(testLine).width;
        
        if (testWidth > maxWidth && i > 0) {
            lines.push(line.trim());
            line = words[i] + ' ';
        } else {
            line = testLine;
        }
    }
    
    lines.push(line.trim());
    return lines;
}

function autoWrapAndShrinkToFit(ctx, text, x, y, maxWidth, maxHeight, initialFontSize, minFontSize, textAlign, fontFamily, lineSpacingMultiplier) {
    if (lineSpacingMultiplier === undefined || lineSpacingMultiplier === null) lineSpacingMultiplier = 1.2;
    var fontSize = initialFontSize;
    var wrappedLines = [];
    var lineHeight;
    
    while (true) {
        ctx.font = fontSize + "px " + fontFamily;
        wrappedLines = getWrappedLines(ctx, text, maxWidth);
        lineHeight = fontSize * lineSpacingMultiplier;
        var totalHeight = wrappedLines.length * lineHeight;
        
        if (totalHeight <= maxHeight) {
            break;
        } else if (fontSize <= minFontSize) {
            break;
        }
        
        fontSize--;
    }
    
    ctx.font = fontSize + "px " + fontFamily;
    ctx.textAlign = textAlign || "center";
    // Use alphabetic baseline for cross-device consistency (iOS Safari has bugs with "middle")
    ctx.textBaseline = "alphabetic";
    
    var totalTextHeight = wrappedLines.length * lineHeight;
    var sampleMetrics = ctx.measureText(wrappedLines[0] || text);
    var verticalOffset;
    if (typeof sampleMetrics.actualBoundingBoxAscent === 'number' && typeof sampleMetrics.actualBoundingBoxDescent === 'number') {
        var ascent = sampleMetrics.actualBoundingBoxAscent;
        var descent = sampleMetrics.actualBoundingBoxDescent;
        verticalOffset = ascent - (ascent + descent) / 2;
    } else {
        verticalOffset = fontSize * 0.35;
    }
    var startY = y - (totalTextHeight / 2) + (lineHeight / 2) + verticalOffset;
    
    for (var i = 0; i < wrappedLines.length; i++) {
        ctx.fillText(wrappedLines[i], x, startY + i * lineHeight);
    }
}

function addTextToCanvasGirls(canvas, texts) {
    const ctx = canvas.getContext('2d');
    
    texts.forEach((textEntry) => {
        const fontSize = textEntry.fontSize || 35;
        const color = textEntry.color || "#000000";
        const fontFamily = "'NotoSansArabic', sans-serif";
        const align = textEntry.center.a || "center";
        const x = textEntry.center.x;
        const y = textEntry.center.y;
        const lineSpacingMultiplier = textEntry.lineSpacing || 1.2;
        
        ctx.fillStyle = color;
        
        if (textEntry.maxHeight && textEntry.maxHeight > 0) {
            autoWrapAndShrinkToFit(
                ctx,
                textEntry.text,
                x,
                y,
                textEntry.maxWidth || 300,
                textEntry.maxHeight,
                fontSize,
                12,
                align,
                fontFamily,
                lineSpacingMultiplier
            );
        } else {
            ctx.font = fontSize + "px " + fontFamily;
            ctx.textAlign = align;
            // Use alphabetic baseline for cross-device consistency (iOS Safari has bugs with "middle")
            ctx.textBaseline = "alphabetic";
            var singleMetrics = ctx.measureText(textEntry.text);
            var singleOffset;
            if (typeof singleMetrics.actualBoundingBoxAscent === 'number' && typeof singleMetrics.actualBoundingBoxDescent === 'number') {
                var asc = singleMetrics.actualBoundingBoxAscent;
                var desc = singleMetrics.actualBoundingBoxDescent;
                singleOffset = asc - (asc + desc) / 2;
            } else {
                singleOffset = fontSize * 0.35;
            }
            ctx.fillText(textEntry.text, x, y + singleOffset);
        }
    });
}

async function fetchCertificateImageGirls(imageIndex, textParams) {
    // Wait for font to be loaded before any canvas text rendering
    await ensureFontLoaded();
    const response = await fetch('https://k.tahdiri.com/public/assets/js/im2.php?i=' + imageIndex);
    const base64ImageData = await response.text();
    
    return new Promise(function(resolve) {
        var img = new Image();
        img.src = base64ImageData;
        img.onload = function() {
            var canvas = document.createElement('canvas');
            canvas.width = img.width;
            canvas.height = img.height;
            var ctx = canvas.getContext('2d');
            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
            addTextToCanvasGirls(canvas, textParams);
            resolve(canvas.toDataURL('image/png'));
        };
    });
}

