    try {
        var imageData = await fetchCertificateImageGirls(currentPreviewDataGirls.imageIndex, currentPreviewDataGirls.originalTextParams);
        imgEl.src = imageData;
        imgEl.style.display = 'block';
        loadingEl.style.display = 'none';
    } catch (err) {
        loadingEl.textContent = 'خطأ في تحميل الصورة';
        loadingEl.style.color = '#f44336';
    }
