var bulkSendModalAddedGirls = false;
var bulkSendDataGirls = null;

function selectAllStudentsGirls(select) {
    document.querySelectorAll('#bulkStudentListGirls input[type="checkbox"]').forEach(cb => cb.checked = select);
}

async function sendCertificatesToAllClass(templateIndex, getParamsFunc, button) {
    if (!bulkSendModalAddedGirls) {
        document.body.insertAdjacentHTML('beforeend', bulkSendModalHTMLGirls);
        bulkSendModalAddedGirls = true;
    }
    
    const students = [];
    document.querySelectorAll('b').forEach(b => {
        const name = b.innerText.trim();
        if (name && name.length > 1) students.push(name);
    });
    
    bulkSendDataGirls = { templateIndex, getParamsFunc, students, button };
    
    const listContainer = document.getElementById('bulkStudentListGirls');
    listContainer.innerHTML = students.map((name, i) => 
        '<label style="display:block; padding:5px; border-bottom:1px solid #eee; cursor:pointer;">' +
        '<input type="checkbox" checked value="' + i + '" style="margin-left:10px;">' + name + '</label>'
    ).join('');
    
    document.getElementById('bulkProgressGirls').style.display = 'none';
    document.getElementById('bulkSendLoaderGirls').style.display = 'none';
    document.getElementById('bulkSendButtonsGirls').style.display = 'flex';
    
    document.getElementById('bulkSendModalGirls').style.display = 'block';
    
    document.getElementById('startBulkSendBtnGirls').onclick = startBulkSendGirls;
}

async function startBulkSendGirls() {
    if (!bulkSendDataGirls) return;
    
    const checkboxes = document.querySelectorAll('#bulkStudentListGirls input[type="checkbox"]:checked');
    const selectedIndices = Array.from(checkboxes).map(cb => parseInt(cb.value));
    
    if (selectedIndices.length === 0) {
        alert('يرجى اختيار طالبة واحدة على الأقل');
        return;
    }
    
    const msgTitle = document.getElementById('bulkMsgTitleGirls').value;
    const msgBody = document.getElementById('bulkMsgBodyGirls').value;
    
    document.getElementById('bulkSendButtonsGirls').style.display = 'none';
    document.getElementById('bulkSendLoaderGirls').style.display = 'block';
    document.getElementById('bulkProgressGirls').style.display = 'block';
    
    const progressBar = document.getElementById('bulkProgressBarGirls');
    const progressText = document.getElementById('bulkProgressTextGirls');
    
    let successCount = 0;
    let failCount = 0;
    
    for (let i = 0; i < selectedIndices.length; i++) {
        const studentName = bulkSendDataGirls.students[selectedIndices[i]];
        const params = bulkSendDataGirls.getParamsFunc(studentName);
        
        const percent = Math.round(((i + 1) / selectedIndices.length) * 100);
        progressBar.style.width = percent + '%';
        progressBar.textContent = percent + '%';
        progressText.textContent = 'جاري إرسال: ' + studentName + ' (' + (i + 1) + '/' + selectedIndices.length + ')';
        
        try {
            await sendCertificateToParentSilentGirls(bulkSendDataGirls.templateIndex, params, studentName, msgTitle, msgBody);
            successCount++;
        } catch (err) {
            console.error('Failed for ' + studentName + ':', err);
            failCount++;
        }
        
        await new Promise(r => setTimeout(r, 500));
    }
    
    document.getElementById('bulkSendLoaderGirls').style.display = 'none';
    progressText.textContent = 'تم الإرسال بنجاح: ' + successCount + ' | فشل: ' + failCount;
    
    if (successCount > 0) {
        bulkSendDataGirls.button.innerHTML = 'تم الإرسال ✓';
        bulkSendDataGirls.button.style.backgroundColor = '#4CAF50';
    }
    
    setTimeout(() => {
        document.getElementById('bulkSendModalGirls').style.display = 'none';
    }, 2000);
}

async function sendCertificateToParentSilentGirls(imageIndex, textParams, studentName, msgTitle, msgBody) {
    const schoolId = window.top.document.getElementById("hSchoolId")?.value || 
                     new URLSearchParams(window.top.location.search).get('schoolId');
    const csrfToken = window.top.document.getElementById("csrfid")?.value || window.top.csrfToken;
    
    if (!schoolId || !csrfToken) throw new Error("بيانات المدرسة غير متوفرة");
    
    const base64Image = await fetchCertificateImageGirls(imageIndex, textParams);
    const blob = await (await fetch(base64Image)).blob();
    const file = new File([blob], studentName.trim() + "_certificate.png", { type: "image/png" });
    
    const waData = window.top.wa || [];
    const cleanName = (str) => str?.replace(/[\n\r]+/g, ' ').replace(/\s+/g, ' ').trim() || "";
    const normalizeArabic = (text) => cleanName(text).replace(/[أإآ]/g, 'ا').replace(/ة/g, 'ه').replace(/ى/g, 'ي');
    const normalizeKey = (text) => cleanName(text).toLowerCase().replace(/\s/g, '');
    
    const studentEntry = waData.find(s => normalizeArabic(s[0]) === normalizeArabic(studentName.trim()));
    if (!studentEntry) throw new Error("لم يتم العثور على الطالبة");
    
    const studentAccount = studentEntry[4];
    
    const fetchDom = async (url) => {
        const res = await fetch(url);
        const html = await res.text();
        return new DOMParser().parseFromString(html, 'text/html');
    };
    
    let guardianName = null;
    let page = 1;
    let hasNextPage = true;
    
    while (hasNextPage && !guardianName) {
        const doc = await fetchDom("https://schools.madrasati.sa/SchoolManagmentReports/StudentInfo/ClassStudentInfo/" + schoolId + "?page=" + page);
        const tables = doc.querySelectorAll('table');
        
        for (let t of tables) {
            const headers = Array.from(t.querySelectorAll('th')).map(th => cleanName(th.textContent));
            const accountIndex = headers.findIndex(h => h.includes('حساب الطالب'));
            const guardianIndex = headers.findIndex(h => h.includes('ولي الأمر'));
            
            if (accountIndex > -1 && guardianIndex > -1) {
                const rows = t.querySelectorAll('tbody tr');
                for (let row of rows) {
                    const cells = row.querySelectorAll('td');
                    if (cells.length > Math.max(accountIndex, guardianIndex)) {
                        const rawAccount = cleanName(cells[accountIndex].textContent);
                        if (normalizeKey(rawAccount) === normalizeKey(studentAccount)) {
                            guardianName = cleanName(cells[guardianIndex].textContent);
                            break;
                        }
                    }
                }
            }
        }
        
        const nextBtn = doc.querySelector('.pagination li:last-child:not(.disabled) a');
        if (nextBtn && nextBtn.href) page++; else hasNextPage = false;
    }
    
    if (!guardianName) throw new Error("لم يتم العثور على ولي الأمر");
    
    const sendMsgDoc = await fetchDom("https://schools.madrasati.sa/SystemUser/Communication/SendMessage?SchoolId=" + schoolId);
    const sendToken = sendMsgDoc.querySelector('input[name="__RequestVerificationToken"]')?.value;
    
    let guardianId = null;
    const guardianNorm = normalizeArabic(guardianName);
    const userOptions = sendMsgDoc.querySelectorAll('#ToUsers option');
    for (let opt of userOptions) {
        if (opt.value && normalizeArabic(opt.textContent) === guardianNorm) {
            guardianId = opt.value;
            break;
        }
    }
    
    if (!guardianId) throw new Error("لم يتم العثور على ولي الأمر في القائمة");
    
    const fd = new FormData();
    fd.append('file0', file, file.name);
    const uploadRes = await fetch("https://schools.madrasati.sa/SystemUser/Communication/AttachFile?fileType=Image&fileTitle=" + encodeURIComponent("شهادة " + studentName.trim()), {
        method: 'POST',
        headers: { "requestverificationtoken": csrfToken, "x-requested-with": "XMLHttpRequest" },
        body: fd
    });
    const uploadData = await uploadRes.json();
    if (!uploadData.success) throw new Error("فشل رفع الصورة");
    
    const formBody = new URLSearchParams({
        Id: 0, AttachType: 0, IsTemp: true, FilePath: uploadData.url,
        ActionType: "addad", txt_UploadUrl: "/SystemUser/Communication/AttachFile",
        Name: uploadData.filename, "__RequestVerificationToken": csrfToken
    });
    const validateRes = await fetch("https://schools.madrasati.sa/SystemUser/Communication/UploaderForm", {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: formBody
    });
    const validateData = await validateRes.json();
    if (!validateData.success) throw new Error("فشل التحقق من الصورة");
    
    const payload = new URLSearchParams();
    payload.append('ToUsersEnc', guardianId);
    payload.append('Subject', msgTitle || 'شهادة ' + studentName.trim());
    payload.append('Body', window.top.Base64?.encode('<p>' + (msgBody || 'مرفق شهادة التفوق') + '</p>') || btoa('<p>' + (msgBody || 'مرفق شهادة التفوق') + '</p>'));
    payload.append('SchoolId', schoolId);
    payload.append('IsTeacher', 'False');
    payload.append('__RequestVerificationToken', sendToken);
    payload.append('AttachmentFiles[0].AttachType', 0);
    payload.append('AttachmentFiles[0].FilePath', validateData.model.FilePath);
    payload.append('AttachmentFiles[0].Name', validateData.model.Name);
    
    const sendRes = await fetch("https://schools.madrasati.sa/SystemUser/Communication/SendMessage", {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: payload
    });
    const sendData = await sendRes.json();
    
    if (!sendData || sendData.success !== true) {
        throw new Error(sendData?.msg || "فشل الإرسال");
    }
}
