// =========== التحقق من أن الحقل يحتوي على مسمى وليس اسم ===========
function validateTitle(input, fieldName) {
    const value = input.value.trim();
    const words = value.split(/s+/).filter(w => w.length > 0);
    if (words.length > 1) {
        if (!confirm('تنبيه: حقل "' + fieldName + '" مخصص للمسمى فقط (مثل: المعلم أو المديرة) وليس الاسم الكامل.\n\nهل تريد المتابعة بهذه القيمة؟')) {
            input.value = words[0]; // Keep only first word
        }
    }
}

