var previewModalAdded = false;
var currentPreviewData = null;

function showPreviewModal(imageIndex, textParams, studentName, button, getUpdatedParams) {
    if (!previewModalAdded) {
        document.body.insertAdjacentHTML('beforeend', previewModalHTML);
        previewModalAdded = true;
    }
    
    currentPreviewData = {
        imageIndex: imageIndex,
        originalTextParams: textParams,
        studentName: studentName,
        button: button
    };
    
    document.getElementById('previewMsgTitle').value = 'شهادة ' + studentName.trim();
    document.getElementById('previewMsgBody').value = 'مرفق شهادة التفوق';
    document.getElementById('previewStudentName').textContent = 'الطالب/ة: ' + studentName;
    
    // Reset UI state
    document.getElementById('sendingLoader').style.display = 'none';
    document.getElementById('sendButtons').style.display = 'flex';
    document.getElementById('closePreviewBtn').style.display = 'block';
    document.getElementById('confirmSendBtn').disabled = false;
    
    document.getElementById('certPreviewModal').style.display = 'block';
    
    loadPreviewImage();
    
    document.getElementById('confirmSendBtn').onclick = function() {
        sendCertificateFromModal();
    };
}

async function loadPreviewImage() {
    if (!currentPreviewData) return;
    
    var imgEl = document.getElementById('previewCertImage');
    var loadingEl = document.getElementById('previewImageLoading');
    
    imgEl.style.display = 'none';
    loadingEl.style.display = 'block';
    loadingEl.textContent = 'جاري تحميل الصورة...';
    
    try {
        var imageData = await fetchCertificateImage(currentPreviewData.imageIndex, currentPreviewData.originalTextParams);
        imgEl.src = imageData;
        imgEl.style.display = 'block';
        loadingEl.style.display = 'none';
    } catch (err) {
        loadingEl.textContent = 'خطأ في تحميل الصورة';
        loadingEl.style.color = '#f44336';
    }
}

function closePreviewModal() {
    document.getElementById('certPreviewModal').style.display = 'none';
}

async function sendCertificateFromModal() {
    if (!currentPreviewData) return;
    
    var msgTitle = document.getElementById('previewMsgTitle').value;
    var msgBody = document.getElementById('previewMsgBody').value;
    var btn = currentPreviewData.button;
    
    // Show loader, hide buttons
    document.getElementById('sendingLoader').style.display = 'block';
    document.getElementById('sendButtons').style.display = 'none';
    document.getElementById('closePreviewBtn').style.display = 'none';
    
    try {
        await sendCertificateToParentDirect(
            currentPreviewData.imageIndex, 
            currentPreviewData.originalTextParams, 
            currentPreviewData.studentName, 
            btn,
            msgTitle,
            msgBody
        );
        
        // Success - close modal and button already updated by sendCertificateToParentDirect
        closePreviewModal();
        
    } catch (err) {
        // Error - show buttons again
        document.getElementById('sendingLoader').style.display = 'none';
        document.getElementById('sendButtons').style.display = 'flex';
        document.getElementById('closePreviewBtn').style.display = 'block';
        alert('خطأ في الإرسال: ' + err.message);
    }
}

