// =========== إرسال شهادة للوالدين مباشرة ===========
async function sendCertificateToParentDirect(imageIndex, textParams, studentName, button, msgTitle, msgBody) {
    button.disabled = true;
    button.innerHTML = "جاري الإرسال...";
    
    try {
        // 1. Get context
        const schoolId = window.top.document.getElementById("hSchoolId")?.value || 
                         new URLSearchParams(window.top.location.search).get('schoolId');
        const csrfToken = window.top.document.getElementById("csrfid")?.value || window.top.csrfToken;
        
        if (!schoolId || !csrfToken) {
            throw new Error("بيانات المدرسة غير متوفرة");
        }
        
        // 2. Generate image blob
        const base64Image = await fetchCertificateImage(imageIndex, textParams);
        const blob = await (await fetch(base64Image)).blob();
        const file = new File([blob], studentName.trim() + "_certificate.png", { type: "image/png" });
        
        // 3. Find student's parent
        const waData = window.top.wa || [];
        const cleanName = (str) => str?.replace(/[\n\r]+/g, ' ').replace(/\s+/g, ' ').trim() || "";
        const normalizeArabic = (text) => cleanName(text).replace(/[أإآ]/g, 'ا').replace(/ة/g, 'ه').replace(/ى/g, 'ي');
        const normalizeKey = (text) => cleanName(text).toLowerCase().replace(/\s/g, '');
        
        const studentEntry = waData.find(s => normalizeArabic(s[0]) === normalizeArabic(studentName.trim()));
        if (!studentEntry) {
            throw new Error("لم يتم العثور على الطالب: " + studentName);
        }
        
        const studentAccount = studentEntry[4];
        
        // 4. Fetch guardian info from report
        const fetchDom = async (url) => {
            const res = await fetch(url);
            const html = await res.text();
            return new DOMParser().parseFromString(html, 'text/html');
        };
        
        let guardianName = null;
        let page = 1;
        let hasNextPage = true;
        
        while (hasNextPage && !guardianName) {
            const doc = await fetchDom("https://schools.madrasati.sa/SchoolManagmentReports/StudentInfo/ClassStudentInfo/" + schoolId + "?page=" + page);
            const tables = doc.querySelectorAll('table');
            
            for (let t of tables) {
                const headers = Array.from(t.querySelectorAll('th')).map(th => cleanName(th.textContent));
                const accountIndex = headers.findIndex(h => h.includes('حساب الطالب'));
                const guardianIndex = headers.findIndex(h => h.includes('ولي الأمر'));
                
                if (accountIndex > -1 && guardianIndex > -1) {
                    const rows = t.querySelectorAll('tbody tr');
                    for (let row of rows) {
                        const cells = row.querySelectorAll('td');
                        if (cells.length > Math.max(accountIndex, guardianIndex)) {
                            const rawAccount = cleanName(cells[accountIndex].textContent);
                            if (normalizeKey(rawAccount) === normalizeKey(studentAccount)) {
                                guardianName = cleanName(cells[guardianIndex].textContent);
                                break;
                            }
                        }
                    }
                }
            }
            
            const nextBtn = doc.querySelector('.pagination li:last-child:not(.disabled) a');
            if (nextBtn && nextBtn.href) page++; else hasNextPage = false;
        }
        
        if (!guardianName) {
            throw new Error("لم يتم العثور على ولي الأمر للطالب");
        }
        
        // 5. Get guardian ID from dropdown
        const sendMsgDoc = await fetchDom("https://schools.madrasati.sa/SystemUser/Communication/SendMessage?SchoolId=" + schoolId);
        const sendToken = sendMsgDoc.querySelector('input[name="__RequestVerificationToken"]')?.value;
        
        let guardianId = null;
        const guardianNorm = normalizeArabic(guardianName);
        const userOptions = sendMsgDoc.querySelectorAll('#ToUsers option');
        for (let opt of userOptions) {
            if (opt.value && normalizeArabic(opt.textContent) === guardianNorm) {
                guardianId = opt.value;
                break;
            }
        }
        
        if (!guardianId) {
            throw new Error("لم يتم العثور على ولي الأمر في القائمة");
        }
        
        // 6. Upload image
        const fd = new FormData();
        fd.append('file0', file, file.name);
        const uploadRes = await fetch("https://schools.madrasati.sa/SystemUser/Communication/AttachFile?fileType=Image&fileTitle=" + encodeURIComponent("شهادة " + studentName.trim()), {
            method: 'POST',
            headers: { "requestverificationtoken": csrfToken, "x-requested-with": "XMLHttpRequest" },
            body: fd
        });
        const uploadData = await uploadRes.json();
        if (!uploadData.success) throw new Error(uploadData.msg || "فشل رفع الصورة");
        
        // 7. Validate upload
        const formBody = new URLSearchParams({
            Id: 0, AttachType: 0, IsTemp: true, FilePath: uploadData.url,
            ActionType: "addad", txt_UploadUrl: "/SystemUser/Communication/AttachFile",
            Name: uploadData.filename, "__RequestVerificationToken": csrfToken
        });
        const validateRes = await fetch("https://schools.madrasati.sa/SystemUser/Communication/UploaderForm", {
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body: formBody
        });
        const validateData = await validateRes.json();
        if (!validateData.success) throw new Error("فشل التحقق من الصورة");
        
        // 8. Send message
        const payload = new URLSearchParams();
        payload.append('ToUsersEnc', guardianId);
        payload.append('Subject', msgTitle || 'شهادة ' + studentName.trim());
        payload.append('Body', window.top.Base64?.encode('<p>' + (msgBody || 'مرفق شهادة التفوق') + '</p>') || btoa('<p>' + (msgBody || 'مرفق شهادة التفوق') + '</p>'));
        payload.append('SchoolId', schoolId);
        payload.append('IsTeacher', 'False');
        payload.append('__RequestVerificationToken', sendToken);
        payload.append('AttachmentFiles[0].AttachType', 0);
        payload.append('AttachmentFiles[0].FilePath', validateData.model.FilePath);
        payload.append('AttachmentFiles[0].Name', validateData.model.Name);
        
        const sendRes = await fetch("https://schools.madrasati.sa/SystemUser/Communication/SendMessage", {
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body: payload
        });
        const sendData = await sendRes.json();
        
        if (sendData && sendData.success === true) {
            button.innerHTML = "تم الإرسال ✓";
            button.style.backgroundColor = "#4CAF50";
        } else {
            throw new Error(sendData.msg || "فشل الإرسال");
        }
        
    } catch (err) {
        console.error(err);
        alert("خطأ: " + err.message);
        button.innerHTML = "إرسال";
        button.disabled = false;
    }
}

// =========== Helper functions for canvas text ===========
function getWrappedLines(ctx, text, maxWidth) {
    const words = text.split(' ');
    let line = '';
    const lines = [];
    
    for (let i = 0; i < words.length; i++) {
        const testLine = line + words[i] + ' ';
        const testWidth = ctx.measureText(testLine).width;
        
        if (testWidth > maxWidth && i > 0) {
            lines.push(line.trim());
            line = words[i] + ' ';
        } else {
            line = testLine;
        }
    }
    
    lines.push(line.trim());
    return lines;
}

function autoWrapAndShrinkToFit(ctx, text, x, y, maxWidth, maxHeight, initialFontSize, minFontSize, textAlign, fontFamily, lineSpacingMultiplier) {
    if (lineSpacingMultiplier === undefined || lineSpacingMultiplier === null) lineSpacingMultiplier = 1.2;
    var fontSize = initialFontSize;
    var wrappedLines = [];
    var lineHeight;
    
    while (true) {
        ctx.font = fontSize + "px " + fontFamily;
        wrappedLines = getWrappedLines(ctx, text, maxWidth);
        lineHeight = fontSize * lineSpacingMultiplier;
        var totalHeight = wrappedLines.length * lineHeight;
        
        if (totalHeight <= maxHeight) {
            break;
        } else if (fontSize <= minFontSize) {
            break;
        }
        
        fontSize--;
    }
    
    ctx.font = fontSize + "px " + fontFamily;
    ctx.textAlign = textAlign || "center";
    // Use alphabetic baseline for cross-device consistency (iOS Safari has bugs with "middle")
    ctx.textBaseline = "alphabetic";
    
    var totalTextHeight = wrappedLines.length * lineHeight;
    var sampleMetrics = ctx.measureText(wrappedLines[0] || text);
    var verticalOffset;
    if (typeof sampleMetrics.actualBoundingBoxAscent === 'number' && typeof sampleMetrics.actualBoundingBoxDescent === 'number') {
        var ascent = sampleMetrics.actualBoundingBoxAscent;
        var descent = sampleMetrics.actualBoundingBoxDescent;
        verticalOffset = ascent - (ascent + descent) / 2;
    } else {
        verticalOffset = fontSize * 0.35;
    }
    var startY = y - (totalTextHeight / 2) + (lineHeight / 2) + verticalOffset;
    
    for (var i = 0; i < wrappedLines.length; i++) {
        ctx.fillText(wrappedLines[i], x, startY + i * lineHeight);
    }
}

function addTextToCanvas(canvas, texts) {
    const ctx = canvas.getContext('2d');
    
    texts.forEach((textEntry) => {
        const fontSize = textEntry.fontSize || 35;
        const color = textEntry.color || "#000000";
        const fontFamily = "'NotoSansArabic', sans-serif";
        const align = textEntry.center.a || "center";
        const x = textEntry.center.x;
        const y = textEntry.center.y;
        const lineSpacingMultiplier = textEntry.lineSpacing || 1.2;
        
        ctx.fillStyle = color;
        
        if (textEntry.maxHeight && textEntry.maxHeight > 0) {
            autoWrapAndShrinkToFit(
                ctx,
                textEntry.text,
                x,
                y,
                textEntry.maxWidth || 300,
                textEntry.maxHeight,
                fontSize,
                12,
                align,
                fontFamily,
                lineSpacingMultiplier
            );
        } else {
            ctx.font = fontSize + "px " + fontFamily;
            ctx.textAlign = align;
            // Use alphabetic baseline for cross-device consistency (iOS Safari has bugs with "middle")
            ctx.textBaseline = "alphabetic";
            var singleMetrics = ctx.measureText(textEntry.text);
            var singleOffset;
            if (typeof singleMetrics.actualBoundingBoxAscent === 'number' && typeof singleMetrics.actualBoundingBoxDescent === 'number') {
                var asc = singleMetrics.actualBoundingBoxAscent;
                var desc = singleMetrics.actualBoundingBoxDescent;
                singleOffset = asc - (asc + desc) / 2;
            } else {
                singleOffset = fontSize * 0.35;
            }
            ctx.fillText(textEntry.text, x, y + singleOffset);
        }
    });
}
// =========== End Helper functions ===========

// Ensure font is loaded for canvas rendering outside iframe (preview/send)
var _externalFontPromise = null;
function ensureFontLoaded() {
    if (_externalFontPromise) return _externalFontPromise;
    var fontUrl = 'https://fonts.gstatic.com/s/notosansarabic/v28/nwpCtLGrOAZMl5nJ_wfgRg3DrWFZWsnVBJ_sS6tlqHHFlj4wv4o.woff2';
    
    function fallbackLoad() {
        return fetch(fontUrl).then(function(r) { return r.blob(); }).then(function(blob) {
            return new Promise(function(resolve) {
                var reader = new FileReader();
                reader.onloadend = function() {
                    var b64 = reader.result.split(',')[1];
                    var css = '@font-face { font-family: "NotoSansArabic"; src: url(data:font/woff2;base64,' + b64 + ') format("woff2"); }';
                    var s = document.createElement('style'); s.textContent = css; document.head.appendChild(s);
                    if (document.fonts && document.fonts.ready) { document.fonts.ready.then(function() { resolve(true); }); }
                    else { setTimeout(function() { resolve(true); }, 500); }
                };
                reader.readAsDataURL(blob);
            });
        }).catch(function() { return false; });
    }
    
    if (typeof FontFace !== 'undefined') {
        _externalFontPromise = fetch(fontUrl).then(function(r) { return r.arrayBuffer(); }).then(function(buf) {
            var f = new FontFace('NotoSansArabic', buf); return f.load();
        }).then(function(loaded) {
            document.fonts.add(loaded); return true;
        }).catch(function() { return fallbackLoad(); });
    } else {
        _externalFontPromise = fallbackLoad();
    }
    return _externalFontPromise;
}

async function fetchCertificateImage(imageIndex, textParams) {
    // Wait for font to be loaded before any canvas text rendering
    await ensureFontLoaded();
    const response = await fetch('https://k.tahdiri.com/public/assets/js/im2.php?i=' + imageIndex);
    const base64ImageData = await response.text();
    
    return new Promise(function(resolve) {
        var img = new Image();
        img.src = base64ImageData;
        img.onload = function() {
            var canvas = document.createElement('canvas');
            canvas.width = img.width;
            canvas.height = img.height;
            var ctx = canvas.getContext('2d');
            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
            addTextToCanvas(canvas, textParams);
            resolve(canvas.toDataURL('image/png'));
        };
    });
}

